out=Path('assets/generated'); out.mkdir(parents=True, exist_ok=True)
base='''<svg xmlns="http://www.w3.org/2000/svg" width="1536" height="1024" viewBox="0 0 1536 1024"><defs><linearGradient id="g" x1="0" x2="1" y1="0" y2="1"><stop stop-color="#071426"/><stop offset=".55" stop-color="#101827"/><stop offset="1" stop-color="#0b2a3a"/></linearGradient><style>.h{font:700 74px Georgia,serif;fill:#f5efe2}.s{font:500 28px Arial,sans-serif;fill:#91a4b8}.m{font:700 34px Arial,sans-serif;fill:#f4b04a}.l{stroke:#2b8cff;stroke-width:2;opacity:.55}.a{fill:#2b8cff;opacity:.18}.b{fill:#f4b04a;opacity:.9}.box{fill:#101d2f;stroke:#28415e;stroke-width:2;rx:20}.t{font:600 22px Arial,sans-serif;fill:#f5efe2}.p{font:18px Arial,sans-serif;fill:#9fb1c5}</style></defs><rect width="1536" height="1024" fill="url(#g)"/>CONTENT</svg>'''
hero='''<g opacity=".7">'''+''.join(f'<path class="l" d="M{80+i*90} 120 C {180+i*35} 360,{480+i*12} 450,{1450-i*30} {180+i*45}"/>' for i in range(12))+'''</g><circle cx="1130" cy="310" r="210" class="a"/><circle cx="1190" cy="360" r="8" class="b"/><path d="M960 470 l130-210 240 86 68 210-220 136z" fill="none" stroke="#2b8cff" stroke-width="4" opacity=".75"/><text x="96" y="230" class="m">FIRST DRAFT INVESTOR BRIEF</text><text x="96" y="345" class="h">Top 10 AI Companies</text><text x="96" y="435" class="h">to Invest in — H2 2026</text><text x="100" y="510" class="s">Compute bottlenecks • model economics • application-layer breakouts • regulation</text>'''
layout='''<text x="80" y="90" class="m">Company Profile Page System</text><rect x="80" y="130" width="300" height="160" class="box"/><text x="115" y="215" class="t">LOGO / ID</text><rect x="410" y="130" width="1040" height="160" class="box"/><text x="445" y="180" class="t">Key metrics: revenue • growth • GM • valuation • stage</text><g>'''+''.join(f'<rect x="{445+i*190}" y="215" width="150" height="38" fill="#172840"/><text x="{462+i*190}" y="241" class="p">Metric {i+1}</text>' for i in range(5))+'''</g><rect x="80" y="330" width="650" height="300" class="box"/><text x="115" y="385" class="t">Investment thesis</text><path d="M120 440 h540 M120 500 h520 M120 560 h480" stroke="#91a4b8"/><rect x="760" y="330" width="690" height="300" class="box"/><text x="795" y="385" class="t">Risk callouts / bear case</text><circle cx="820" cy="455" r="9" fill="#d85b53"/><circle cx="820" cy="515" r="9" fill="#d85b53"/><circle cx="820" cy="575" r="9" fill="#d85b53"/><rect x="80" y="670" width="1370" height="260" class="box"/><text x="115" y="725" class="t">Valuation table + catalysts + nearest rivals</text><path d="M120 770 h1280 M120 830 h1280 M120 890 h1280" stroke="#28415e"/>'''
viz='''<text x="80" y="90" class="m">Data Visualization Style Frame</text><rect x="80" y="140" width="640" height="340" class="box"/><text x="120" y="195" class="t">Revenue growth</text><polyline points="130,410 240,360 350,300 460,250 580,185 660,165" fill="none" stroke="#2b8cff" stroke-width="7"/><rect x="800" y="140" width="650" height="340" class="box"/><text x="840" y="195" class="t">Funding rounds</text><line x1="880" y1="330" x2="1360" y2="330" stroke="#91a4b8" stroke-width="4"/>'''+''.join(f'<circle cx="{900+i*110}" cy="330" r="{18+i*3}" fill="#f4b04a"/><text x="{880+i*110}" y="395" class="p">R{i+1}</text>' for i in range(5))+'''<rect x="80" y="540" width="640" height="340" class="box"/><text x="120" y="595" class="t">Market share</text>'''+''.join(f'<rect x="150" y="{645+i*50}" width="{360-i*55}" height="28" fill="#2b8cff" opacity="{.85-i*.09}"/>' for i in range(5))+'''<rect x="800" y="540" width="650" height="340" class="box"/><text x="840" y="595" class="t">EV/Sales vs growth</text>'''+''.join(f'<circle cx="{900+i*85}" cy="{790-(i%4)*45}" r="13" fill="#3fbf7f"/>' for i in range(6))+''''''
palette='''<text x="80" y="90" class="m">Color + Typography System</text>'''+''.join(f'<rect x="{90+i*205}" y="160" width="160" height="160" rx="18" fill="{c}"/><text x="{90+i*205}" y="355" class="p">{n}</text>' for i,(c,n) in enumerate([('#071426','Deep navy'),('#101827','Graphite'),('#f5efe2','Warm ivory'),('#2b8cff','AI blue'),('#f4b04a','Signal amber'),('#d85b53','Risk red'),('#3fbf7f','Growth green')]))+'''<text x="100" y="560" style="font:700 80px Georgia,serif;fill:#f5efe2">Editorial serif for judgment</text><text x="105" y="640" style="font:400 34px Arial,sans-serif;fill:#91a4b8">Neutral sans for metrics, source notes, and risk language</text><path d="M100 720 h900" stroke="#2b8cff" stroke-width="6"/><path d="M100 765 h650" stroke="#f4b04a" stroke-width="6"/>'''
for name,content in {'hero-cover.svg':hero,'company-profile-layout.svg':layout,'data-viz-style-frame.svg':viz,'palette-typography.svg':palette}.items():
    (out/name).write_text(base.replace('CONTENT',content))
    print(out/name)
